script:
frappe.ui.form.on('Assessment Booking', {
    // 1. Jalankan inisiasi saat dokumen dibuka
    refresh: function(frm) {
        // Tombol sinkronisasi manual opsional dari server
        frm.add_custom_button(__('Cek Status Kuota Terbaru'), function() {
            frm.reload_doc();
        }).addClass('btn-primary');

        let current_fullname = frappe.session.user_fullname;
        
        frappe.db.get_value('Muhafizh', { 'muhafizh_name': current_fullname }, ['name'])
            .then(r => {
                if (r.message) {
                    frm.current_muhafizh_id = r.message.name;
                    
                    // Auto-fill Muhafizh Name pada baris kosong yang sudah ada jika belum terisi
                    if (frm.doc.student_list) {
                        frm.doc.student_list.forEach(row => {
                            if (!row.muhafizh_name) {
                                frappe.model.set_value(row.doctype, row.name, 'muhafizh_name', frm.current_muhafizh_id);
                            }
                        });
                        frm.refresh_field('student_list');
                    }
                }
            });
    },

    // 2. Setup filter dinamis saat grid/baris diakses
    setup: function(frm) {
        // Filter HALAQAH ID berdasarkan muhafizh_name di baris yang sama
        frm.set_query('halaqah_id', 'student_list', function(doc, cdt, cdn) {
            let row = locals[cdt][cdn];
            
            // Kita gunakan pemicu asinkronus internal Frappe set_query menggunakan Promise
            if (row.muhafizh_name) {
                return frappe.db.get_doc('Muhafizh', row.muhafizh_name).then(muhafizh_doc => {
                    let allowed_halaqahs = [];
                    if (muhafizh_doc.halaqah_group) {
                        allowed_halaqahs = muhafizh_doc.halaqah_group.map(d => d.halaqah_group);
                    }
                    return {
                        filters: {
                            'name': ['in', allowed_halaqahs.length ? allowed_halaqahs : ['']]
                        }
                    };
                });
            }
        });

        // Filter STUDENT berdasarkan Halaqah ID di baris yang sama
        frm.set_query('student', 'student_list', function(doc, cdt, cdn) {
            let row = locals[cdt][cdn];
            if (row.halaqah_id) {
                return {
                    query: "frappe.desk.search.search_link",
                    filters: {
                        'halaqah_id': row.halaqah_id
                    }
                };
            }
        });
    }
});

// 3. Logika khusus pada level baris Child Table (Assessment Booking Student)
frappe.ui.form.on('Assessment Booking Student', {
    // Auto-fill Muhafizh Name ketika baris baru ditambahkan manual oleh Muhafizh
    student_list_add: function(frm, cdt, cdn) {
        if (frm.current_muhafizh_id) {
            frappe.model.set_value(cdt, cdn, 'muhafizh_name', frm.current_muhafizh_id);
        }
    },

    // Auto-fill Muhafizh Name sebagai cadangan saat form grid baris di-render
    form_render: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (!row.muhafizh_name && frm.current_muhafizh_id) {
            frappe.model.set_value(cdt, cdn, 'muhafizh_name', frm.current_muhafizh_id);
        }
    },
    
    // Reset Student jika Halaqah ID diubah agar data tidak mismatch
    halaqah_id: function(frm, cdt, cdn) {
        frappe.model.set_value(cdt, cdn, 'student', '');
    }
});

frappe.ui.form.on('Tahfizh Log', {
    onload: function(frm) {
        set_halaqah_filter(frm);
        set_student_filter(frm);
    },
    muhafizh_id: function(frm) {
        set_halaqah_filter(frm);
    },
    halaqah_id: function(frm) {
        set_student_filter(frm);
        // Otomatis kosongkan isian Student jika user mengubah Halaqah ID agar tidak miss-match
        frm.set_value('student', '');
    }
});

function set_halaqah_filter(frm) {
    if (frm.doc.muhafizh_id) {
        frappe.db.get_doc('Muhafizh', frm.doc.muhafizh_id)
            .then(muhafizh_doc => {
                let allowed_halaqahs = [];
                if (muhafizh_doc.halaqah_group) {
                    allowed_halaqahs = muhafizh_doc.halaqah_group.map(row => row.halaqah_group);
                }
                frm.set_query('halaqah_id', function() {
                    return {
                        filters: {
                            'name': ['in', allowed_halaqahs.length ? allowed_halaqahs : ['']]
                        }
                    };
                });
                frm.refresh_field('halaqah_id');
            });
    } else {
        frm.set_query('halaqah_id', function() {
            return { filters: { 'name': ['in', ['']] } };
        });
        frm.refresh_field('halaqah_id');
    }
}

function set_student_filter(frm) {
    if (frm.doc.halaqah_id) {
        frappe.db.get_doc('Halaqah Group', frm.doc.halaqah_id)
            .then(halaqah_doc => {
                let allowed_students = [];
                
                // Mengambil dari child table table_tahfizh_student sesuai struktur Halaqah Group
                if (halaqah_doc.table_tahfizh_student) {
                    allowed_students = halaqah_doc.table_tahfizh_student.map(row => row.student_id);
                }
                
                frm.set_query('student', function() {
                    return {
                        filters: {
                            'name': ['in', allowed_students.length ? allowed_students : ['']]
                        }
                    };
                });
                frm.refresh_field('student');
            });
    } else {
        // CELAH DITUTUP: Jika halaqah_id kosong, paksa filter mencari ID kosong sehingga dropdown tidak menampilkan siapa pun
        frm.set_query('student', function() {
            return {
                filters: {
                    'name': ['in', ['']]
                }
            };
        });
        frm.refresh_field('student');
    }
}

frappe.ui.form.on('Tahfizh Log', {
    onload: function (frm) {
        if (frm.is_new()) {
            // 1. Ambil field email langsung dari data User yang sedang login
            frappe.db.get_value('User', frappe.session.user, 'email')
                .then(res => {
                    let current_email = res && res.message ? res.message.email : "";
                    let current_fullname = "";

                    if (current_email && current_email.includes('@')) {
                        // 2. Potong domain email, ubah titik menjadi spasi, lalu jadikan Title Case
                        let namePart = current_email.split('@')[0].replace(/\./g, ' ').toLowerCase();
                        current_fullname = namePart.replace(/(^\w{1})|(\s+\w{1})/g, letter => letter.toUpperCase());
                    }

                    if (current_fullname) {
                        // 3. Cari ke Master Muhafizh berdasarkan nama hasil konversi email
                        frappe.db.get_value('Muhafizh', { 'muhafizh_name': current_fullname }, ['name', 'muhafizh_name'])
                            .then(r => {
                                if (r && r.message && r.message.name) {
                                    frm.set_value('muhafizh_id', r.message.name);
                                    frm.set_value('muhafizh_name', r.message.muhafizh_name);
                                    frm.set_df_property('muhafizh_name', 'read_only', 1);
                                    frm.set_df_property('muhafizh_name', 'description', '');
                                } else {
                                    frm.set_df_property('muhafizh_name', 'read_only', 0);
                                    let warning_msg = `<span style="color:var(--text-color); font-size: 12px;">
                                        <span style="color:red;"><b>Catatan:</b></span> Nama dari email <b>(${current_fullname})</b> tidak ditemukan di Master Muhafizh. Silakan pilih manual.
                                    </span>`;
                                    frm.set_df_property('muhafizh_name', 'description', warning_msg);
                                }
                            });
                    }
                });
        }
    }
});

frappe.ui.form.on('Tahfizh Log', {
    refresh: function(frm) {
        // Jalankan pengecekan saat halaman pertama kali dimuat
        toggle_continuity_field(frm);
    },
    log_type: function(frm) {
        // Jalankan pengecekan secara instan saat dropdown Log Type diubah
        toggle_continuity_field(frm);
    }
});

// Fungsi khusus untuk mengunci field Continuity saja jika memilih Tahsin
function toggle_continuity_field(frm) {
    let is_tahsin = (frm.doc.log_type === 'Tahsin');
    
    // Hanya continuity yang diset read-only jika Log Type = Tahsin
    frm.set_df_property('continuity', 'read_only', is_tahsin ? 1 : 0);
    
    // Opsional: Otomatis mengosongkan nilai continuity jika user pindah ke Tahsin
    if (is_tahsin) {
        frm.set_value('continuity', '');
    }
}

frappe.ui.form.on('Tahfizh Log', {
    page: function (frm) {
        // Picu hitungan saat angka Page diketik/diubah
        calculate_total_line(frm);
    },
    line: function (frm) {
        // Picu hitungan saat angka Line diketik/diubah
        calculate_total_line(frm);
    }
});

function calculate_total_line(frm) {
    let page = frm.doc.page || 0;
    let line = frm.doc.line || 0;
    
    // Hitung matematika murni (pembulatan diatur lewat precision DocType)
    let total_line = (page * 15) + line;
    
    frm.set_value('total_line', total_line);
}

frappe.ui.form.on('Tahfizh Log', {
    student: function(frm) {
        fetch_last_tahfizh_log(frm);
    },
    log_type: function(frm) {
        fetch_last_tahfizh_log(frm);
    },
    surah_start: function(frm) {
        if (frm.doc.surah_start) {
            frm.set_value('surah_end', frm.doc.surah_start);
        }
    }
});

function fetch_last_tahfizh_log(frm) {
    if (!frm.doc.student || !frm.doc.log_type) {
        return;
    }

    // Ambil data log terakhir berdasarkan kombinasi Student & Log Type yang sedang dipilih saat ini
    frappe.db.get_list('Tahfizh Log', {
        filters: {
            student: frm.doc.student,
            log_type: frm.doc.log_type,
            docstatus: ['<', 2]
        },
        fields: ['surah_end', 'end_ayat', 'tajwid', 'makhraj'],
        order_by: 'creation desc',
        limit: 1
    }).then(records => {
        if (records && records.length > 0) {
            let last_log = records[0];

            // 1. Auto-fill Surah & Ayat (Selalu mengambil dari tipe log yang sama)
            if (last_log.surah_end) {
                frm.set_value('surah_start', last_log.surah_end);
                frm.set_value('surah_end', last_log.surah_end); 
            }
            if (last_log.end_ayat) {
                frm.set_value('start_ayat', last_log.end_ayat);
            }

            // 2. Auto-fill Tajwid & Makhraj (Sesuai aturan baru kamu)
            if (frm.doc.log_type === 'Ziyadah') {
                // Ziyadah mengambil dari data Ziyadah sebelumnya (sudah ter-filter di atas)
                frm.set_value('tajwid', last_log.tajwid || '');
                frm.set_value('makhraj', last_log.makhraj || '');
            } else if (frm.doc.log_type === 'Sabqi') {
                // Sabqi mengambil dari data Sabqi sebelumnya (sudah ter-filter di atas)
                frm.set_value('tajwid', last_log.tajwid || '');
                frm.set_value('makhraj', last_log.makhraj || '');
            } else if (frm.doc.log_type === 'Tahsin') {
                // Tahsin dikosongkan total agar diisi manual
                frm.set_value('tajwid', '');
                frm.set_value('makhraj', '');
            }
        } else {
            // Jika tidak ada data sebelumnya yang cocok dengan kombinasi Student + Log Type ini
            frm.set_value('surah_start', '');
            frm.set_value('surah_end', '');
            frm.set_value('start_ayat', '');
            frm.set_value('tajwid', '');
            frm.set_value('makhraj', '');
        }
    });
}

frappe.ui.form.on('Tahfizh Log', {
    student: function(frm) {
        fetch_last_tahfizh_log(frm);
    },
    log_type: function(frm) {
        fetch_last_tahfizh_log(frm);
    },
    surah_start: function(frm) {
        if (frm.doc.surah_start) {
            frm.set_value('surah_end', frm.doc.surah_start);
        }
    },

    // 1. CEGAT LANGSUNG KETIKA START AYAT DIKETIK
    start_ayat: async function(frm) {
        if (!frm.doc.surah_start && frm.doc.start_ayat) {
            frappe.msgprint(__('Silakan pilih <b>Surah Start</b> terlebih dahulu sebelum mengisi ayat.'));
            frm.set_value('start_ayat', ''); 
            return; 
        }

        if (frm.doc.surah_start && frm.doc.start_ayat) {
            let r = await frappe.db.get_value('Quran Surah Master', frm.doc.surah_start, 'total_ayat');
            if (r && r.message) {
                let max_ayat = r.message.total_ayat || 0;
                if (frm.doc.start_ayat > max_ayat) {
                    frappe.msgprint(__('<b>Start Ayat</b> melebihi batas! Surah {0} hanya memiliki {1} ayat.', [frm.doc.surah_start, max_ayat]));
                    frm.set_value('start_ayat', ''); 
                }
            }
        }
    },

    // 2. CEGAT LANGSUNG KETIKA END AYAT DIKETIK
    end_ayat: async function(frm) {
        if (!frm.doc.surah_end && frm.doc.end_ayat) {
            frappe.msgprint(__('Silakan pilih <b>Surah End</b> terlebih dahulu sebelum mengisi ayat.'));
            frm.set_value('end_ayat', ''); 
            return;
        }

        if (frm.doc.surah_end && frm.doc.end_ayat) {
            let r = await frappe.db.get_value('Quran Surah Master', frm.doc.surah_end, 'total_ayat');
            if (r && r.message) {
                let max_ayat = r.message.total_ayat || 0;
                if (frm.doc.end_ayat > max_ayat) {
                    frappe.msgprint(__('<b>End Ayat</b> melebihi batas! Surah {0} hanya memiliki {1} ayat.', [frm.doc.surah_end, max_ayat]));
                    frm.set_value('end_ayat', ''); 
                    return; 
                }
            }
        }

        if (frm.doc.surah_start === frm.doc.surah_end && frm.doc.start_ayat && frm.doc.end_ayat) {
            if (frm.doc.end_ayat < frm.doc.start_ayat) {
                frappe.msgprint(__('<b>End Ayat</b> tidak boleh lebih kecil dari <b>Start Ayat</b> pada surah yang sama.'));
                frm.set_value('end_ayat', ''); 
            }
        }
    },

    // 3. PERTAHANAN FINAL SAAT TOMBOL SAVE DITEKAN
    validate: function(frm) {
        return new Promise(async (resolve, reject) => {
            let is_valid = true;

            if (frm.doc.start_ayat && !frm.doc.surah_start) {
                frappe.msgprint(__('<b>Gagal Simpan:</b> Surah Start harus diisi.'));
                is_valid = false;
            }
            if (frm.doc.end_ayat && !frm.doc.surah_end) {
                frappe.msgprint(__('<b>Gagal Simpan:</b> Surah End harus diisi.'));
                is_valid = false;
            }

            if (frm.doc.surah_start && frm.doc.start_ayat) {
                let r1 = await frappe.db.get_value('Quran Surah Master', frm.doc.surah_start, 'total_ayat');
                if (r1 && r1.message && frm.doc.start_ayat > r1.message.total_ayat) {
                    frappe.msgprint(__('<b>Gagal Simpan:</b> Start Ayat melebihi batas maksimal surah.'));
                    is_valid = false;
                }
            }

            if (frm.doc.surah_end && frm.doc.end_ayat) {
                let r2 = await frappe.db.get_value('Quran Surah Master', frm.doc.surah_end, 'total_ayat');
                if (r2 && r2.message && frm.doc.end_ayat > r2.message.total_ayat) {
                    frappe.msgprint(__('<b>Gagal Simpan:</b> End Ayat melebihi batas maksimal surah.'));
                    is_valid = false;
                }
            }

            if (frm.doc.surah_start === frm.doc.surah_end && frm.doc.start_ayat && frm.doc.end_ayat) {
                if (frm.doc.end_ayat < frm.doc.start_ayat) {
                    frappe.msgprint(__('<b>Gagal Simpan:</b> End Ayat lebih kecil dari Start Ayat.'));
                    is_valid = false;
                }
            }

            if (is_valid) {
                resolve(); 
            } else {
                reject(); 
            }
        });
    }
});

function fetch_last_tahfizh_log(frm) {
    if (!frm.doc.student || !frm.doc.log_type) {
        return;
    }

    frappe.db.get_list('Tahfizh Log', {
        filters: {
            student: frm.doc.student,
            log_type: frm.doc.log_type,
            docstatus: ['<', 2]
        },
        fields: ['surah_end', 'end_ayat', 'tajwid', 'makhraj'],
        order_by: 'creation desc',
        limit: 1
    }).then(records => {
        if (records && records.length > 0) {
            let last_log = records[0];

            if (last_log.surah_end) {
                frm.set_value('surah_start', last_log.surah_end);
                frm.set_value('surah_end', last_log.surah_end); 
            }
            if (last_log.end_ayat) {
                frm.set_value('start_ayat', last_log.end_ayat);
            }

            if (frm.doc.log_type === 'Ziyadah' || frm.doc.log_type === 'Sabqi') {
                frm.set_value('tajwid', last_log.tajwid || '');
                frm.set_value('makhraj', last_log.makhraj || '');
            } else if (frm.doc.log_type === 'Tahsin') {
                frm.set_value('tajwid', '');
                frm.set_value('makhraj', '');
            }
        } else {
            frm.set_value('surah_start', '');
            frm.set_value('surah_end', '');
            frm.set_value('start_ayat', '');
            frm.set_value('tajwid', '');
            frm.set_value('makhraj', '');
        }
    });
}

frappe.ui.form.on('Tahfizh Log', {
    after_save: function (frm) {
        // Membuka form baru kosong secara otomatis setelah sukses save
        frappe.new_doc('Tahfizh Log');
    }
});

frappe.ui.form.on('Tahfizh Student', {
    refresh: function(frm) {
        if (!frm.is_new()) {
            load_logs_into_tab(frm);
        }
    }
});

function load_logs_into_tab(frm) {
    frappe.db.get_list('Tahfizh Log', {
        filters: {
            student: frm.doc.name, 
            docstatus: ['<', 2] 
        },
        // Menarik nama surah dari master data menggunakan Alias
        fields: [
            'name', 'date', 'log_type', 
            'surah_start', 'surah_start.surah_name as nama_surah_start', 'start_ayat', 
            'surah_end', 'surah_end.surah_name as nama_surah_end', 'end_ayat', 
            'continuity', 'tajwid', 'makhraj', 'total_line', 'muhafizh_name'
        ],
        // FIX ERROR AMBIGUOUS: Menggunakan 'name' agar database tidak bingung
        order_by: 'date desc, name desc', 
        limit: 50 
    }).then(records => {
        
        if (!records || records.length === 0) {
            frm.fields_dict.tahfizh_log_preview.html(
                '<div class="text-muted text-center" style="padding: 40px;">Belum ada riwayat log setoran untuk santri ini.</div>'
            );
            return;
        }

        let table_html = `
            <div style="overflow-x: auto; margin-top: 10px;">
                <table class="table table-bordered table-hover" style="background-color: white;">
                    <thead>
                        <tr class="text-muted" style="background-color: var(--bg-light-gray); font-weight: bold; text-align: center;">
                            <th style="width: 120px;">Date</th>
                            <th style="width: 80px;">Type</th>
                            <th>Start (Surah : Ayat)</th>
                            <th>End (Surah : Ayat)</th>
                            <th title="Continuity" style="width: 40px;">C</th>
                            <th title="Tajwid" style="width: 40px;">T</th>
                            <th title="Makhraj" style="width: 40px;">M</th>
                            <th style="width: 70px;">Line</th>
                            <th style="width: 150px;">Muhafizh</th>
                        </tr>
                    </thead>
                    <tbody>
        `;

        records.forEach(row => {
            let badge_class = row.log_type === 'Ziyadah' ? 'green' : (row.log_type === 'Sabqi' ? 'blue' : 'orange');
            let display_date = frappe.datetime.str_to_user(row.date);
            
            // Logika: Jika nama_surah berhasil ditarik, gunakan itu. Jika gagal, tetap tampilkan angkanya agar tidak blank.
            let text_start = row.nama_surah_start || row.surah_start;
            let text_end = row.nama_surah_end || row.surah_end;

            let start_info = row.surah_start ? `${text_start} : ${row.start_ayat || '0'}` : '-';
            let end_info = row.surah_end ? `${text_end} : ${row.end_ayat || '0'}` : '-';

            table_html += `
                <tr>
                    <td class="text-center">${display_date}</td>
                    <td class="text-center"><span class="label label-${badge_class}">${row.log_type}</span></td>
                    <td>${start_info}</td>
                    <td>${end_info}</td>
                    <td class="text-center">${row.continuity || '-'}</td>
                    <td class="text-center">${row.tajwid || '-'}</td>
                    <td class="text-center">${row.makhraj || '-'}</td>
                    <td class="text-center">${row.total_line || 0}</td>
                    <td>${row.muhafizh_name || '-'}</td>
                </tr>
            `;
        });

        table_html += `
                    </tbody>
                </table>
            </div>
            <div class="text-muted text-right" style="margin-top: 5px;">
                <small>* C: Continuity, T: Tajwid, M: Makhraj</small>
            </div>
        `;

        frm.fields_dict.tahfizh_log_preview.html(table_html);
    });
}

frappe.ui.form.on('Assessment Log', {
    student: function(frm) {
        if (frm.doc.student) {
            
            // Panggil data full milik santri tersebut dari server
            frappe.call({
                method: 'frappe.client.get',
                args: {
                    doctype: 'Tahfizh Student',
                    name: frm.doc.student
                },
                callback: function(r) {
                    // Cek apakah ada data di tabel anak 'halaqah_group'
                    if (r.message && r.message.halaqah_group && r.message.halaqah_group.length > 0) {
                        
                        let baris_pertama = r.message.halaqah_group[0];
                        
                        // KUNCI PERUBAHAN: Menarik data menggunakan fieldname baru (muhafizh_name)
                        let nama_guru = baris_pertama.muhafizh_name; 
                        
                        if (nama_guru) {
                            // Menembakkan nilai tersebut ke form Assessment Log
