// Fungsi untuk mengecek dan memasang kembali Halaqah ID jika belum lewat 2 jam
function check_and_apply_saved_halaqah(frm) {
    // Hanya berlaku untuk dokumen yang BENAR-BENAR BARU (belum pernah di-save)
    if (frm.doc.__islocal) {
        let saved_id = localStorage.getItem('saved_murajaah_halaqah_id');
        let saved_time = localStorage.getItem('saved_murajaah_halaqah_time');
        
        if (saved_id && saved_time) {
            let current_time = new Date().getTime();
            let hours_passed = (current_time - saved_time) / (1000 * 60 * 60);
            
            // Konfigurasi durasi penguncian: 2 Jam
            if (hours_passed < 2) {
                frm.set_value('halaqah_id', saved_id);
            } else {
                // Jika sudah lewat 2 jam, hapus penyimpanan agar ter-reset
                localStorage.removeItem('saved_murajaah_halaqah_id');
                localStorage.removeItem('saved_murajaah_halaqah_time');
            }
        }
    }
}

