frappe.ui.form.on('Murajaah Log', {
    // 1. Saat Porsi Ujian dipilih (Rubu', Nisf, Juz)
    portion: function(frm) {
        frm.set_value('part', '');
        clear_surah_fields(frm);

        let options = [""]; // Opsi kosong default
        if (frm.doc.portion === "Rubu' (1/4)") {
            options = ["", "Q1", "Q2", "Q3", "Q4"];
        } else if (frm.doc.portion === "Nisf (1/2)") {
            options = ["", "H1", "H2"];
        } else if (frm.doc.portion === "Juz (1)") {
            options = ["Full"];
            frm.set_value('part', 'Full');
        }

        frm.set_df_property('part', 'options', options);
        frm.refresh_field('part');
    },

    // 2. Validasi input angka Juz (MEMBLOKIR ANGKA 0 & LUAR JANGKAUAN)
    juz: function(frm) {
        if (frm.doc.juz === "" || frm.doc.juz === null || frm.doc.juz === undefined) {
            clear_surah_fields(frm);
            return;
        }

        // Blokir angka 0 atau di luar range 1-30
        if (frm.doc.juz < 1 || frm.doc.juz > 30) {
            frappe.msgprint(__('Nomor Juz harus antara 1 sampai 30 (Tidak boleh 0).'));
            frm.set_value('juz', '', null, false);
            clear_surah_fields(frm);
            return;
        }
        
        // Jika part sudah terisi, langsung jalankan penarikan data master
        if (frm.doc.part) {
            frm.trigger('part');
        }
    },

    // 3. Ambil Data dari Master saat Part dipilih
    part: function(frm) {
        if (!frm.doc.part || !frm.doc.juz || !frm.doc.portion) {
            clear_surah_fields(frm);
            return;
        }

        let target_dt = "";
        if (frm.doc.portion === "Rubu' (1/4)") {
            target_dt = "Quran Quarter Master Data";
        } else if (frm.doc.portion === "Nisf (1/2)") {
            target_dt = "Quran Half Master Data";
        } else if (frm.doc.portion === "Juz (1)") {
            target_dt = "Quran Juz Master Data 2";
        }

        if (!target_dt) return;

        frappe.db.get_value(target_dt, {"juz_number": frm.doc.juz}, "name")
            .then(r => {
                if (r.message && r.message.name) {
                    let master_name = r.message.name;

                    if (frm.doc.portion === "Juz (1)") {
                        frappe.db.get_doc(target_dt, master_name).then(m_doc => {
                            set_fields_with_surah_name(frm, m_doc);
                        });
                    } 
                    else {
                        frappe.model.with_doc(target_dt, master_name, function() {
                            let m_doc = frappe.model.get_doc(target_dt, master_name);
                            let row = null;

                            if (frm.doc.portion === "Rubu' (1/4)") {
                                row = m_doc.juz_content.find(d => d.quarter === frm.doc.part);
                            } else if (frm.doc.portion === "Nisf (1/2)") {
                                row = m_doc.juz_content.find(d => d.half === frm.doc.part);
                            }

                            if (row) {
                                set_fields_with_surah_name(frm, row);
                            } else {
                                frappe.msgprint(__("Data Part tidak ditemukan di Master Data"));
                                clear_surah_fields(frm);
                            }
                        });
                    }
                } else {
                    frappe.msgprint(__("Juz {0} belum ada di {1}", [frm.doc.juz, target_dt]));
                    clear_surah_fields(frm);
                }
            });
    }
});

