function toggle_questions_by_portion(frm) {
    // 1. Jika PORTION BELUM DIPILIH, sembunyikan SEMUA pertanyaan (1-5) agar rapi
    if (!frm.doc.portion) {
        for (let i = 1; i <= 5; i++) {
            frm.toggle_display('continuity_' + i, false);
            frm.toggle_display('tajwid_' + i, false);
            frm.toggle_display('makhraj_' + i, false);
        }
        return;
    }

    // 2. Jika Portion adalah Rubu' (1/4), TAMPILKAN 1-3 dan SEMBUNYIKAN 4-5
    if (frm.doc.portion === "Rubu' (1/4)") {
        // Tampilkan Q1 - Q3
        for (let i = 1; i <= 3; i++) {
            frm.toggle_display('continuity_' + i, true);
            frm.toggle_display('tajwid_' + i, true);
            frm.toggle_display('makhraj_' + i, true);
        }
        // Sembunyikan Q4 - Q5
        for (let i = 4; i <= 5; i++) {
            frm.toggle_display('continuity_' + i, false);
            frm.toggle_display('tajwid_' + i, false);
            frm.toggle_display('makhraj_' + i, false);
        }
    } 
    // 3. Jika Portion adalah Nisf (1/2) atau Juz (1), TAMPILKAN SEMUA (1-5)
    else if (frm.doc.portion === "Nisf (1/2)" || frm.doc.portion === "Juz (1)") {
        for (let i = 1; i <= 5; i++) {
            frm.toggle_display('continuity_' + i, true);
            frm.toggle_display('tajwid_' + i, true);
            frm.toggle_display('makhraj_' + i, true);
        }
    }
}

