frappe.ui.form.on('Assessment Booking', {
    refresh: function(frm) {
        setTimeout(() => {
            let $wrapper = $(frm.fields_dict['student_list'].wrapper);
            $wrapper.find('.btn-assessment-log').remove();
            
            let $btn = $('<button type="button" class="btn btn-default btn-xs btn-assessment-log" style="margin-left: 10px;">Assessment Log</button>');
            
            $btn.on('click', function() {
                // Mengambil semua baris yang dicentang secara manual dari DOM
                let checked_rows = [];
                $wrapper.find('.grid-row-check:checked').each(function() {
                    let idx = $(this).closest('.grid-row').attr('data-idx');
                    // Mengambil data dari frm.doc berdasarkan index
                    checked_rows.push(frm.doc.student_list[idx - 1]);
                });
                
                // Validasi jumlah
                if (checked_rows.length === 0) {
                    frappe.msgprint(__('Silakan centang minimal satu baris siswa.'));
                    return;
                }
                if (checked_rows.length > 1) {
                    frappe.msgprint(__('Silakan pilih hanya satu baris untuk membuat Assessment Log.'));
                    return;
                }
                
                let selected_row = checked_rows[0];
                
                // Validasi Status (Pastikan penulisan 'Approved' sama persis dengan di sistem)
                if (selected_row.status !== 'Approved') {
                    frappe.msgprint(__('Hanya baris dengan status "Approved" yang bisa diproses. Status saat ini: ' + selected_row.status));
                    return;
                }
                
                // Eksekusi
                frappe.new_doc('Assessment Log', {
                    student: selected_row.student,
                    juz: selected_row.juz
                });
            });
            
            $wrapper.find('.grid-add-row').after($btn);
        }, 500);
    }
});

frappe.ui.form.on('Assessment Booking', {
    // 1. Ambil data Muhafizh sejak awal
    onload: function(frm) {
        let current_fullname = frappe.session.user_fullname;
        
        frappe.db.get_value('Muhafizh', { 'muhafizh_name': current_fullname }, ['name'])
            .then(r => {
                if (r && r.message) {
                    frm.current_muhafizh_id = r.message.name;
                    
                    frappe.db.get_doc('Muhafizh', frm.current_muhafizh_id).then(muhafizh_doc => {
                        let allowed_halaqahs = [];
                        if (muhafizh_doc.halaqah_group) {
                            allowed_halaqahs = muhafizh_doc.halaqah_group.map(d => d.halaqah_group);
                        }
                        
                        frm.set_query('halaqah_id', 'student_list', function() {
                            return { filters: { 'name': ['in', allowed_halaqahs.length ? allowed_halaqahs : ['']] } };
                        });
                    });
                }
            });
    },

    refresh: function(frm) {
        if (frm.current_muhafizh_id && frm.doc.student_list) {
            frm.doc.student_list.forEach(row => {
                if (!row.muhafizh_name) {
                    frappe.model.set_value(row.doctype, row.name, 'muhafizh_name', frm.current_muhafizh_id);
                }
            });
            frm.refresh_field('student_list');
        }
    },

    // 2. Filter Student yang Jauh Lebih Tangguh
    setup: function(frm) {
        frm.set_query('student', 'student_list', function(doc, cdt, cdn) {
            let row = locals[cdt][cdn];
            
            // Jika memori baris sudah memiliki daftar siswa yang diizinkan
            if (row.allowed_students && row.allowed_students.length > 0) {
                return {
                    filters: {
                        'name': ['in', row.allowed_students]
                    }
                };
            }
            
            // Tampilkan kosong jika halaqah belum dipilih atau data belum siap
            return { filters: { 'name': ['in', ['Tidak ada data (Pilih Halaqah ID dulu)']] } };
        });
    },

    validate: function(frm) {
        if (frm.doc.student_list) {
            let valid = true;
            frm.doc.student_list.forEach(row => {
                if (row.juz !== "" && row.juz !== null && row.juz !== undefined) {
                    if (row.juz < 1 || row.juz > 30) {
                        frappe.msgprint({
                            title: __('Validasi Gagal'),
                            indicator: 'red',
                            message: __('Baris #{0}: Nomor Juz harus antara 1 sampai 30.', [row.idx])
                        });
                        valid = false;
                    }
                }
            });
            if (!valid) frappe.validated = false;
        }
    }
});

