                if (halaqah_doc && halaqah_doc.table_tahfizh_student) {
                    // Deteksi cerdas: gunakan d.student_id ATAU d.student
                    row.allowed_students = halaqah_doc.table_tahfizh_student.map(d => d.student_id || d.student);
                    
                    // Jangan set_value kosong agar tidak mengaktifkan trigger "Set only once" secara prematur
                    frm.refresh_field('student_list');
                }
            });
        } else {
            row.allowed_students = [];
        }
    },

    juz: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.juz !== "" && row.juz !== null && row.juz !== undefined) {
            if (row.juz < 1 || row.juz > 30) {
                frappe.msgprint(__('Nomor Juz harus antara 1 sampai 30.'));
                frappe.model.set_value(cdt, cdn, 'juz', '');
            }
        }
    }
});

