    // Trigger kalkulasi setiap kali salah satu field nilai berubah
    continuity_1: function(frm) { calculate_averages(frm); },
    tajwid_1: function(frm) { calculate_averages(frm); },
    makhraj_1: function(frm) { calculate_averages(frm); },
    
    continuity_2: function(frm) { calculate_averages(frm); },
    tajwid_2: function(frm) { calculate_averages(frm); },
    makhraj_2: function(frm) { calculate_averages(frm); },
    
    continuity_3: function(frm) { calculate_averages(frm); },
    tajwid_3: function(frm) { calculate_averages(frm); },
    makhraj_3: function(frm) { calculate_averages(frm); },
    
    continuity_4: function(frm) { calculate_averages(frm); },
    tajwid_4: function(frm) { calculate_averages(frm); },
    makhraj_4: function(frm) { calculate_averages(frm); },
    
    continuity_5: function(frm) { calculate_averages(frm); },
    tajwid_5: function(frm) { calculate_averages(frm); },
    makhraj_5: function(frm) { calculate_averages(frm); }
});

function calculate_averages(frm) {
    // 1. Hitung Rata-rata Continuity (C) - Pastikan dibaca sebagai Float/Angka
    let total_c = flt(frm.doc.continuity_1) + 
                  flt(frm.doc.continuity_2) + 
                  flt(frm.doc.continuity_3) + 
                  flt(frm.doc.continuity_4) + 
                  flt(frm.doc.continuity_5);
    let avg_c = total_c / 5;
    frm.set_value('continuity', avg_c);

    // 2. Hitung Rata-rata Tajwid (T)
    let total_t = flt(frm.doc.tajwid_1) + 
                  flt(frm.doc.tajwid_2) + 
                  flt(frm.doc.tajwid_3) + 
                  flt(frm.doc.tajwid_4) + 
                  flt(frm.doc.tajwid_5);
    let avg_t = total_t / 5;
    frm.set_value('tajwid', avg_t);

    // 3. Hitung Rata-rata Makhraj (M)
    let total_m = flt(frm.doc.makhraj_1) + 
                  flt(frm.doc.makhraj_2) + 
                  flt(frm.doc.makhraj_3) + 
                  flt(frm.doc.makhraj_4) + 
                  flt(frm.doc.makhraj_5);
    let avg_m = total_m / 5;
    frm.set_value('makhraj', avg_m);

    // 4. Hitung Final Score (Rata-rata C dikalikan 20)
    let final_score = avg_c * 20;
    frm.set_value('score', final_score);
}

