                </table>
            </div>
            <div class="text-muted text-right" style="margin-top: 5px;">
                <small>* C: Continuity, T: Tajwid, M: Makhraj</small>
            </div>
        `;

        preview_field.$wrapper.html(table_html);
    });
}

