function load_assessment_logs_into_tab(frm) {
    frappe.db.get_list('Assessment Log', {
        filters: {
            student: frm.doc.name, 
            docstatus: ['<', 2]
        },
        fields: [
            'name', 'date', 'juz', 'continuity', 'tajwid', 'makhraj', 'score', 'muhafizh_name'
        ],
        order_by: 'date desc, name desc',
        limit: 50
    }).then(records => {
        let preview_field = frm.get_field('assessment_log_preview_html');
        
        if (!preview_field) return;

        if (!records || records.length === 0) {
            preview_field.$wrapper.html(
                '<div class="text-muted text-center" style="padding: 40px;">Belum ada riwayat log assessment untuk santri ini.</div>'
            );
            return;
        }

        let table_html = `
            <div style="overflow-x: auto; margin-top: 10px;">
                <table class="table table-bordered table-hover" style="background-color: white;">
                    <thead>
                        <tr class="text-muted" style="background-color: var(--bg-light-gray); font-weight: bold; text-align: center;">
                            <th style="width: 120px;">Date</th>
                            <th style="width: 80px;">Juz</th>
                            <th title="Continuity" style="width: 40px;">C</th>
                            <th title="Tajwid" style="width: 40px;">T</th>
                            <th title="Makhraj" style="width: 40px;">M</th>
                            <th title="Score" style="width: 50px;">Score</th>
                            <th style="width: 150px;">Assessor</th>
                        </tr>
                    </thead>
                    <tbody>
        `;

        records.forEach(row => {
            let display_date = frappe.datetime.str_to_user(row.date);

            // Ganti flt dengan format standar JavaScript agar tidak crash/kosong
            let val_c = row.continuity ? Number(row.continuity) : '-';
            let val_t = row.tajwid ? Number(row.tajwid) : '-';
            let val_m = row.makhraj ? Number(row.makhraj) : '-';
            let val_score = row.score ? Number(row.score) : '-';

            table_html += `
                <tr>
                    <td class="text-center">${display_date}</td>
                    <td class="text-center" style="font-weight: bold;">${row.juz || '-'}</td>
                    <td class="text-center">${val_c}</td>
                    <td class="text-center">${val_t}</td>
                    <td class="text-center">${val_m}</td>
                    <td class="text-center" style="font-weight: bold; color: #1a73e8;">${val_score}</td>
                    <td>${row.muhafizh_name || '-'}</td>
                </tr>
            `;
        });

        table_html += `
                    </tbody>
                </table>
            </div>
            <div class="text-muted text-right" style="margin-top: 5px;">
                <small>* C: Continuity, T: Tajwid, M: Makhraj</small>
            </div>
        `;

        preview_field.$wrapper.html(table_html);
    });
}

frappe.ui.form.on('Murajaah Log', {
    after_save: function (frm) {
