frappe.ui.form.on('Murajaah Log', {
    refresh: function(frm) {
        calculate_grading(frm);
    },
    portion: function(frm) {
        calculate_grading(frm);
    },
    // Pemicu otomatis setiap kali nilai per soal diubah
    continuity_1: (frm) => calculate_grading(frm), continuity_2: (frm) => calculate_grading(frm), continuity_3: (frm) => calculate_grading(frm), continuity_4: (frm) => calculate_grading(frm), continuity_5: (frm) => calculate_grading(frm),
    tajwid_1: (frm) => calculate_grading(frm), tajwid_2: (frm) => calculate_grading(frm), tajwid_3: (frm) => calculate_grading(frm), tajwid_4: (frm) => calculate_grading(frm), tajwid_5: (frm) => calculate_grading(frm),
    makhraj_1: (frm) => calculate_grading(frm), makhraj_2: (frm) => calculate_grading(frm), makhraj_3: (frm) => calculate_grading(frm), makhraj_4: (frm) => calculate_grading(frm), makhraj_5: (frm) => calculate_grading(frm)
});

function calculate_grading(frm) {
    let count = 0;
    let halaman = 0;
    
    // 1. Tentukan jumlah soal (pembagi) dan total halaman berdasarkan Portion
    if (frm.doc.portion === "Rubu' (1/4)") {
        count = 3;
        halaman = 5;
    } else if (frm.doc.portion === "Nisf (1/2)") {
        count = 5;
        halaman = 10;
    } else if (frm.doc.portion === "Juz (1)") {
        count = 5;
        halaman = 20; // 1 Juz penuh = 20 halaman
    }

    if (count > 0) {
        let total_c = 0, total_t = 0, total_m = 0;

        // 2. Akumulasikan nilai hanya dari soal yang aktif
        for (let i = 1; i <= count; i++) {
            total_c += flt(frm.doc['continuity_' + i]);
            total_t += flt(frm.doc['tajwid_' + i]);
            total_m += flt(frm.doc['makhraj_' + i]);
        }

        // 3. Hitung rata-rata dengan pembulatan 2 angka desimal
        let avg_c = flt(total_c / count, 2);
        let avg_t = flt(total_t / count, 2);
        let avg_m = flt(total_m / count, 2);

        // 4. Masukkan ke field utama di form Murajaah Log (Logika final_score dihapus)
        frm.set_value('continuity', avg_c);
        frm.set_value('tajwid', avg_t);
        frm.set_value('makhraj', avg_m);
    } else {
        // Reset ke 0 jika portion belum ditentukan atau dihapus (Logika reset score dihapus)
        frm.set_value('continuity', 0);
        frm.set_value('tajwid', 0);
        frm.set_value('makhraj', 0);
    }
}
